import { getSupabaseAdmin } from "@/lib/supabase";
import { confirmTossPayment } from "@/lib/toss";

// ─── 답장 시뮬레이터 프롬프트 ───
// 사용자의 답장 초안이 상대방에게 어떻게 먹힐지 예측.
// 부모 심층분석의 결과(psychology, stage, temperature 등)를 맥락으로 주입.
const SIM_PROMPT = `[절대 규칙 - 반드시 지킬 것]
1. 어떤 경우에도 반드시 JSON 형식으로만 응답할 것. JSON 외의 텍스트/설명/질문 절대 금지.
2. 입력 정보가 부족해도 반문 금지. 주어진 맥락만으로 최선의 예측을 해서 JSON 생성.
3. 상대 심리·애착 스타일·관계 단계에 근거해 예측할 것 (추측 아닌 심리학적 추론).

너는 연애 경험 많고 눈치 빠른 친한 언니 "AI언니"야. 사용자가 쓴 답장 초안이 상대방한테 어떻게 먹힐지 시뮬레이션해줘.

존 가트만의 관계 심리학(긍정:부정 상호작용 비율 5:1, 전환 시도 Bids for Connection 반응, 4가지 위험 신호: 비난·방어·경멸·담쌓기, Repair Attempts)과 애착이론(안정형/불안형/회피형 반응 패턴)을 근거로 분석할 것.

말투: 20대~30대 여성 친구한테 편하게 반말. 직설적이되 따뜻하게. 애매하게 말하지 말고 솔직하게.

[예측할 항목]
1. predicted_reaction (2~3문장):
   - 상대방이 실제로 답할 법한 톤·내용을 구체적으로. "~라고 답할 것 같아" 형태로.
   - 상대 애착 스타일(안정/불안/회피)·관계 단계를 반영.

2. emotional_shift:
   - 현재 온도 → 예상 변화 온도. 예: "미지근→따뜻", "따뜻→차가움", "호감→경계", "안정→균열"
   - 현재 상태 정확히 반영 후 변화만 표기.

3. risk_level: "낮음" / "중간" / "높음"
   - 상대가 부담·거리감·불쾌감 느낄 확률.
   - "낮음": 관계에 긍정적, 부담 없음
   - "중간": 상대 성향 따라 갈릴 수 있음
   - "높음": 부담감·경계·오해 유발 가능

4. why (2~3문장):
   - 왜 그렇게 반응할지 심리학 근거로 설명.
   - 가트만 4 Horsemen 출현 여부·Bids for Connection 여부·애착 반응 패턴 인용.
   - 구체적 문구 짚어주기.

5. better_version (3~5문장):
   - 사용자 답안의 의도·톤은 유지하면서 리스크 낮춘 개선 버전.
   - 사용자가 그대로 복사해서 쓸 수 있는 실사용 멘트.
   - 자연스러운 대화체로.

6. one_liner (20자 이내):
   - 친한 언니가 등 쿡 찌르듯 한 문장. 이모지·따옴표 금지.
   - 답안의 핵심 문제/장점을 팩폭.

JSON만 응답:
{"predicted_reaction":"...","emotional_shift":"미지근→따뜻","risk_level":"중간","why":"...","better_version":"...","one_liner":"..."}`;

async function runSimulation(
  parentAnalysis: any,
  parentText: string | null,
  parentImages: any[] | null,
  draftReply: string
) {
  const apiKey = process.env.ANTHROPIC_API_KEY;
  if (!apiKey) throw new Error("ANTHROPIC_API_KEY missing");

  const content: any[] = [];

  // 부모 대화 캡처 이미지를 맥락으로 포함
  if (Array.isArray(parentImages)) {
    for (const img of parentImages) {
      content.push({
        type: "image",
        source: {
          type: "base64",
          media_type: img.mediaType || "image/jpeg",
          data: img.data,
        },
      });
    }
  }

  let prompt = SIM_PROMPT;

  // 기존 대화 맥락 + 이전 분석 결과 + 사용자 답안
  prompt += `\n\n[기존 대화 맥락(사용자가 설명한 상황)]\n${
    parentText?.trim() || "(사용자가 별도 설명하지 않음)"
  }`;

  prompt += `\n\n[이미 분석된 관계 상태 - 이 맥락으로 시뮬레이션할 것]`;
  if (parentAnalysis.score !== undefined)
    prompt += `\n- 현재 호감도: ${parentAnalysis.score}점`;
  if (parentAnalysis.temperature)
    prompt += `\n- 현재 감정 온도: ${parentAnalysis.temperature}`;
  if (parentAnalysis.stage)
    prompt += `\n- 관계 단계: ${parentAnalysis.stage}`;
  if (parentAnalysis.summary)
    prompt += `\n- 언니 한마디: "${parentAnalysis.summary}"`;
  if (parentAnalysis.diagnosis)
    prompt += `\n- 진단: ${parentAnalysis.diagnosis}`;
  if (parentAnalysis.psychology)
    prompt += `\n- 상대 심리: ${parentAnalysis.psychology}`;

  if (parentImages && parentImages.length > 0) {
    prompt += `\n\n(위 첨부 이미지는 기존 대화 캡처. 대화 톤·리듬·텀 파악 시 참고.)`;
  }

  prompt += `\n\n[사용자가 보내려고 쓴 답장 초안]\n"${draftReply}"`;
  prompt += `\n\n이 답장을 실제로 보냈을 때 상대방이 어떻게 반응할지 심리학적으로 시뮬레이션해줘.`;

  content.push({ type: "text", text: prompt });

  const res = await fetch("https://api.anthropic.com/v1/messages", {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      "x-api-key": apiKey,
      "anthropic-version": "2023-06-01",
    },
    body: JSON.stringify({
      model: "claude-sonnet-4-6",
      max_tokens: 1500,
      temperature: 0.3,
      messages: [{ role: "user", content }],
    }),
  });

  if (!res.ok) {
    const errBody = await res.text();
    throw new Error(`Claude API ${res.status}: ${errBody.substring(0, 200)}`);
  }

  const data = await res.json();
  const rawText = data?.content?.[0]?.text || "";
  const match = rawText.match(/\{[\s\S]*\}/);
  if (!match) throw new Error("시뮬 결과 JSON 파싱 실패");
  return JSON.parse(match[0]);
}

// POST /api/simulation/confirm
// 토스 결제 확정 → 부모 분석 맥락 로드 → Claude 시뮬 실행 → 결과 반환
export async function POST(req: Request) {
  try {
    const { paymentKey, sim_order_id, amount } = await req.json();

    if (!paymentKey || !sim_order_id || typeof amount !== "number") {
      return Response.json(
        { error: "paymentKey, sim_order_id, amount가 필요해요" },
        { status: 400 }
      );
    }

    const supabase = getSupabaseAdmin();

    // 1. 시뮬 주문 조회 + 금액 검증 (프론트 위조 방지)
    const { data: sim, error: simErr } = await supabase
      .from("simulations")
      .select("*")
      .eq("sim_order_id", sim_order_id)
      .single();

    if (simErr || !sim) {
      return Response.json(
        { error: "시뮬 주문을 찾을 수 없어요" },
        { status: 404 }
      );
    }

    if (sim.amount !== amount) {
      return Response.json(
        { error: "결제 금액이 주문 금액과 달라요" },
        { status: 400 }
      );
    }

    // 2. 이미 완료 + 결과 있으면 그대로 반환 (멱등성)
    if (sim.status === "completed" && sim.result) {
      return Response.json({
        sim_order_id,
        draft_reply: sim.draft_reply,
        result: sim.result,
      });
    }

    // 3. 아직 paid 아니면 토스 확정 호출
    if (sim.status !== "paid" && sim.status !== "completed") {
      await confirmTossPayment({
        paymentKey,
        orderId: sim_order_id,
        amount,
      });
      await supabase
        .from("simulations")
        .update({
          status: "paid",
          payment_key: paymentKey,
          paid_at: new Date().toISOString(),
          updated_at: new Date().toISOString(),
        })
        .eq("sim_order_id", sim_order_id);
    }

    // 4. 부모 심층분석 맥락 로드 (대화 + 분석결과 + 이미지)
    const { data: parent, error: pErr } = await supabase
      .from("orders")
      .select("analysis_result, input_text, input_images")
      .eq("order_id", sim.parent_order_id)
      .single();

    if (pErr || !parent?.analysis_result) {
      return Response.json(
        { error: "원 분석 데이터를 불러오지 못했어요" },
        { status: 500 }
      );
    }

    // 5. Claude 시뮬레이션 실행
    const result = await runSimulation(
      parent.analysis_result,
      parent.input_text,
      parent.input_images,
      sim.draft_reply
    );

    // 6. 결과 저장
    await supabase
      .from("simulations")
      .update({
        status: "completed",
        result,
        updated_at: new Date().toISOString(),
      })
      .eq("sim_order_id", sim_order_id);

    return Response.json({
      sim_order_id,
      draft_reply: sim.draft_reply,
      result,
    });
  } catch (e: any) {
    console.error("simulation/confirm error:", e);
    return Response.json(
      { error: "시뮬레이션 중 오류", debug: e?.message || String(e) },
      { status: 500 }
    );
  }
}
